const blizzardQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es el nombre del marine terran protagonista de la campa\u00f1a original de StarCraft?",o:["Jim Raynor", "Arcturus Mengsk", "Edmund Duke", "Tychus Findlay"],a:0,exp:"Jim Raynor es uno de los personajes centrales de StarCraft y aparece desde la campa\u00f1a terran original como sheriff convertido en rebelde.",extra:"Raynor empieza como una figura relativamente com\u00fan dentro del universo terran, pero termina convertido en uno de los l\u00edderes m\u00e1s importantes contra la tiran\u00eda de Mengsk y contra amenazas mayores como los zerg y Amon."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n alien\u00edgena de StarCraft est\u00e1 conectada al Enjambre y a la Supermente?",o:["Protoss", "Zerg", "Terran", "Xel Naga"],a:1,exp:"Los zerg son una especie colectiva controlada originalmente por la Supermente, una entidad ps\u00edquica que dirig\u00eda al Enjambre.",extra:"Los zerg se caracterizan por su evoluci\u00f3n biol\u00f3gica extrema, su adaptaci\u00f3n constante y su estructura de colmena. Son uno de los pilares del conflicto central de StarCraft."},
  {t:"m",q:"\u00bfQui\u00e9n se convierte en la Reina de Espadas en StarCraft?",o:["Nova Terra", "Sarah Kerrigan", "Selendis", "Ariel Hanson"],a:1,exp:"Sarah Kerrigan, una fantasma terran, es capturada e infestada por los zerg, convirti\u00e9ndose en la temida Reina de Espadas.",extra:"La transformaci\u00f3n de Kerrigan es uno de los giros m\u00e1s importantes de la saga. Su ca\u00edda, venganza y posterior redenci\u00f3n forman el coraz\u00f3n narrativo de StarCraft y StarCraft II."},
  {t:"m",q:"\u00bfCu\u00e1l es la unidad b\u00e1sica de infanter\u00eda terran en StarCraft?",o:["Zealot", "Marine", "Zergling", "Hydralisk"],a:1,exp:"El Marine es la unidad b\u00e1sica de combate terran, equipada con armadura CMC y rifle gauss.",extra:"Aunque parece una unidad simple, el Marine es una pieza fundamental del juego competitivo por su bajo coste, movilidad con estimulantes y capacidad de escalar con mejoras."},
  {t:"m",q:"\u00bfQu\u00e9 raza de StarCraft utiliza pylons para alimentar sus estructuras?",o:["Terran", "Zerg", "Protoss", "Xel Naga"],a:2,exp:"Los protoss dependen de los pylons para suministrar energ\u00eda a la mayor\u00eda de sus edificios.",extra:"El sistema de pylons refleja la tecnolog\u00eda psi\u00f3nica avanzada de los protoss. En el juego, destruir pylons puede dejar estructuras inutilizadas, una mec\u00e1nica clave en partidas competitivas."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el planeta natal de los protoss?",o:["Aiur", "Korhal", "Char", "Shakuras"],a:0,exp:"Aiur es el mundo natal de los protoss y tiene un enorme valor espiritual y cultural para ellos.",extra:"La ca\u00edda de Aiur ante los zerg es uno de los eventos m\u00e1s traum\u00e1ticos de la historia protoss. Recuperarlo se convierte en una misi\u00f3n simb\u00f3lica y militar de enorme importancia."},
  {t:"m",q:"\u00bfQui\u00e9n lidera a los Hijos de Korhal antes de convertirse en emperador?",o:["Jim Raynor", "Arcturus Mengsk", "Valerian Mengsk", "Gerard DuGalle"],a:1,exp:"Arcturus Mengsk lidera a los Hijos de Korhal como movimiento rebelde antes de fundar el Dominio Terran.",extra:"Mengsk empieza como revolucionario contra la Confederaci\u00f3n, pero termina reproduciendo muchos de los abusos que dec\u00eda combatir. Su traici\u00f3n a Kerrigan define su papel como antagonista."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n cl\u00e1sica de StarCraft introdujo nuevas unidades y continu\u00f3 la historia tras el juego original?",o:["Lord of Destruction", "Brood War", "The Frozen Throne", "Wings of Liberty"],a:1,exp:"StarCraft: Brood War es la expansi\u00f3n cl\u00e1sica de StarCraft y contin\u00faa directamente la guerra entre terran, protoss y zerg.",extra:"Brood War es considerada una de las expansiones m\u00e1s influyentes en la historia de los RTS. Su balance competitivo ayud\u00f3 a convertir StarCraft en un fen\u00f3meno de esports, especialmente en Corea del Sur."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre del l\u00edder protoss que se al\u00eda con Jim Raynor contra amenazas mayores?",o:["Artanis", "Zeratul", "Fenix", "Aldaris"],a:0,exp:"Artanis se convierte en una figura central del liderazgo protoss y colabora con Raynor en varios momentos clave.",extra:"Artanis representa una generaci\u00f3n de protoss m\u00e1s abierta a alianzas externas. Su liderazgo busca superar divisiones antiguas entre facciones protoss."},
  {t:"m",q:"\u00bfQu\u00e9 personaje protoss es conocido por ser un templario oscuro y por descubrir verdades sobre los Xel Naga?",o:["Fenix", "Zeratul", "Tassadar", "Karax"],a:1,exp:"Zeratul es un templario oscuro que descubre informaci\u00f3n crucial sobre los Xel Naga, Amon y el destino de las razas.",extra:"Zeratul funciona como profeta tr\u00e1gico dentro de StarCraft. Sus visiones y sacrificios empujan a otros personajes a enfrentar amenazas c\u00f3smicas."},
  {t:"m",q:"\u00bfQu\u00e9 campa\u00f1a de StarCraft II se centra principalmente en Jim Raynor?",o:["Heart of the Swarm", "Legacy of the Void", "Wings of Liberty", "Nova Covert Ops"],a:2,exp:"Wings of Liberty se centra en Jim Raynor, su rebeli\u00f3n contra Mengsk y su intento de salvar a Kerrigan.",extra:"La campa\u00f1a combina misiones militares, decisiones de tripulaci\u00f3n y una estructura de nave base desde el Hyperion, dando m\u00e1s peso al lado humano del conflicto."},
  {t:"m",q:"\u00bfQu\u00e9 campa\u00f1a de StarCraft II se centra en Sarah Kerrigan y los zerg?",o:["Wings of Liberty", "Heart of the Swarm", "Legacy of the Void", "Brood War"],a:1,exp:"Heart of the Swarm sigue a Kerrigan mientras recupera control sobre el Enjambre y busca venganza.",extra:"Esta campa\u00f1a profundiza en la identidad de Kerrigan: humana, infestada, l\u00edder zerg y figura destinada a enfrentar amenazas m\u00e1s grandes que Mengsk."},
  {t:"m",q:"\u00bfQu\u00e9 campa\u00f1a de StarCraft II se centra en los protoss y Artanis?",o:["Legacy of the Void", "Heart of the Swarm", "Wings of Liberty", "Insurrection"],a:0,exp:"Legacy of the Void se centra en Artanis y en la lucha final de los protoss contra Amon.",extra:"La campa\u00f1a explora la unidad entre facciones protoss divididas, incluyendo templarios, templarios oscuros, purificadores y taldarim."},
  {t:"m",q:"\u00bfQu\u00e9 recurso, junto con los minerales, es fundamental para crear unidades avanzadas en StarCraft?",o:["Oro", "Vespeno", "Cristal arcano", "Esencia demon\u00edaca"],a:1,exp:"El gas vespeno es el segundo recurso principal de StarCraft y se usa para unidades, tecnolog\u00edas y mejoras avanzadas.",extra:"El manejo de minerales y gas vespeno define el ritmo estrat\u00e9gico de una partida. Algunas composiciones requieren mucho gas, mientras otras dependen m\u00e1s de minerales."},
  {t:"m",q:"\u00bfQu\u00e9 unidad zerg peque\u00f1a y r\u00e1pida suele usarse en grandes cantidades desde etapas tempranas?",o:["Zergling", "Ultralisk", "Mutalisk", "Infestor"],a:0,exp:"El Zergling es una unidad b\u00e1sica zerg, r\u00e1pida y barata, ideal para ataques tempranos y presi\u00f3n constante.",extra:"Con mejoras como velocidad metab\u00f3lica, los zerglings se vuelven extremadamente peligrosos. Su fuerza viene menos de cada individuo y m\u00e1s de su n\u00famero y movilidad."},
  {t:"m",q:"\u00bfQu\u00e9 unidad protoss cuerpo a cuerpo es una de las m\u00e1s ic\u00f3nicas de la saga?",o:["Marine", "Zealot", "Roach", "Marauder"],a:1,exp:"El Zealot es la unidad b\u00e1sica de combate cuerpo a cuerpo de los protoss.",extra:"Los zealots representan la disciplina guerrera protoss. Su dise\u00f1o con cuchillas psi\u00f3nicas los volvi\u00f3 una de las siluetas m\u00e1s reconocibles de StarCraft."},
  {t:"m",q:"\u00bfQui\u00e9n es el pr\u00edncipe humano que se convierte en el Rey Ex\u00e1nime en Warcraft III?",o:["Anduin Wrynn", "Arthas Menethil", "Varian Wrynn", "Uther el Iluminado"],a:1,exp:"Arthas Menethil cae en la corrupci\u00f3n de Frostmourne y termina fusion\u00e1ndose con el Rey Ex\u00e1nime.",extra:"La ca\u00edda de Arthas es una de las historias m\u00e1s famosas de Blizzard. Su tragedia mezcla buenas intenciones, orgullo, desesperaci\u00f3n y corrupci\u00f3n progresiva."},
  {t:"m",q:"\u00bfCu\u00e1l es la espada maldita que corrompe a Arthas?",o:["Ashbringer", "Frostmourne", "Doomhammer", "Quel Delar"],a:1,exp:"Frostmourne es la espada r\u00fanica que roba almas y termina corrompiendo a Arthas.",extra:"La frase asociada a Frostmourne, sobre tener hambre, se volvi\u00f3 ic\u00f3nica entre los fans. La espada simboliza el punto de no retorno del personaje."},
  {t:"m",q:"\u00bfQu\u00e9 orco lidera a la Horda hacia Kalimdor en Warcraft III?",o:["Grommash Hellscream", "Thrall", "Garrosh Hellscream", "Gul dan"],a:1,exp:"Thrall gu\u00eda a la Horda hacia Kalimdor siguiendo visiones y buscando un nuevo futuro para su pueblo.",extra:"Thrall redefine a los orcos como algo m\u00e1s que conquistadores sedientos de guerra. Bajo su liderazgo, la Horda busca honor, supervivencia y una identidad renovada."},
  {t:"m",q:"\u00bfQu\u00e9 demonio corrompe a los orcos mediante la sangre demon\u00edaca?",o:["Archimonde", "Kil jaeden", "Mannoroth", "Sargeras"],a:2,exp:"Mannoroth es el se\u00f1or del foso cuya sangre esclaviza a los orcos a la corrupci\u00f3n demon\u00edaca.",extra:"La liberaci\u00f3n de esa maldici\u00f3n, especialmente con el sacrificio de Grommash, es un momento clave para la historia de la Horda."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Warcraft es conocido como el Profeta y gu\u00eda a varias razas contra la Legi\u00f3n Ardiente?",o:["Medivh", "Khadgar", "Antonidas", "Mal ganis"],a:0,exp:"Medivh aparece como el Profeta en Warcraft III, advirtiendo sobre la amenaza de la Legi\u00f3n Ardiente.",extra:"Medivh tiene una historia compleja: fue pose\u00eddo por Sargeras y tuvo un papel tr\u00e1gico en la apertura del Portal Oscuro, pero luego busca redenci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de World of Warcraft introdujo Terrallende como zona principal?",o:["Wrath of the Lich King", "The Burning Crusade", "Cataclysm", "Legion"],a:1,exp:"The Burning Crusade llev\u00f3 a los jugadores a Terrallende, los restos fragmentados de Draenor.",extra:"La expansi\u00f3n introdujo razas como los elfos de sangre y draenei, adem\u00e1s de enfrentar a jugadores con Illidan en el Templo Oscuro."},
  {t:"m",q:"\u00bfQui\u00e9n es el jefe final m\u00e1s emblem\u00e1tico de Wrath of the Lich King?",o:["Illidan Stormrage", "Arthas como Rey Ex\u00e1nime", "Deathwing", "Garrosh Hellscream"],a:1,exp:"Wrath of the Lich King culmina con el enfrentamiento contra Arthas, ya convertido en el Rey Ex\u00e1nime.",extra:"La Ciudadela de la Corona de Hielo y la pelea final contra Arthas son recordadas como uno de los momentos m\u00e1s importantes de World of Warcraft."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n Aspecto se convierte en el gran antagonista de Cataclysm?",o:["Alexstrasza", "Malygos", "Deathwing", "Nozdormu"],a:2,exp:"Deathwing, antes conocido como Neltharion, es el drag\u00f3n Aspecto corrompido que provoca el Cataclismo.",extra:"Su regreso cambia f\u00edsicamente el mundo de Azeroth dentro del juego, redise\u00f1ando zonas cl\u00e1sicas y alterando la experiencia original."},
  {t:"m",q:"\u00bfCu\u00e1l es la capital humana principal de la Alianza en World of Warcraft?",o:["Orgrimmar", "Ventormenta", "Forjaz", "Dalaran"],a:1,exp:"Ventormenta es la capital humana y uno de los centros principales de la Alianza.",extra:"Stormwind o Ventormenta funciona como s\u00edmbolo de la resistencia humana tras guerras, invasiones y reconstrucciones constantes."},
  {t:"m",q:"\u00bfCu\u00e1l es la capital principal de los orcos en Kalimdor?",o:["Lunargenta", "Orgrimmar", "Entra\u00f1as", "Cima del Trueno"],a:1,exp:"Orgrimmar es la capital orca fundada en Durotar y nombrada en honor a Orgrim Doomhammer.",extra:"La ciudad representa la nueva identidad de la Horda tras su llegada a Kalimdor: austera, militar y marcada por la supervivencia en un territorio duro."},
  {t:"m",q:"\u00bfQu\u00e9 clase de World of Warcraft usa formas animales como oso, felino y lech\u00facico lunar?",o:["Cham\u00e1n", "Druida", "Cazador", "Monje"],a:1,exp:"El druida puede transformarse en varias formas animales para cumplir roles de tanque, da\u00f1o, sanaci\u00f3n o utilidad.",extra:"La versatilidad del druida es una de sus marcas hist\u00f3ricas. Su conexi\u00f3n con la naturaleza y el Sue\u00f1o Esmeralda viene del lore de los elfos de la noche."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es el hermano gemelo de Malfurion Stormrage?",o:["Illidan Stormrage", "Kael thas Caminante del Sol", "Tyrande Susurravientos", "Cenarius"],a:0,exp:"Illidan Stormrage es el hermano gemelo de Malfurion y uno de los personajes m\u00e1s ambiguos de Warcraft.",extra:"Illidan ha sido h\u00e9roe, traidor, prisionero y cazador de demonios. Su lema de estar preparado se volvi\u00f3 uno de los m\u00e1s reconocibles de Blizzard."},
  {t:"m",q:"\u00bfQu\u00e9 reina no-muerta lidera a los Renegados durante gran parte de World of Warcraft?",o:["Jaina Proudmoore", "Sylvanas Windrunner", "Tyrande Whisperwind", "Alleria Windrunner"],a:1,exp:"Sylvanas Windrunner lidera a los Renegados tras liberarse del control del Rey Ex\u00e1nime.",extra:"Sylvanas es uno de los personajes m\u00e1s controvertidos de Warcraft. Su historia pasa de v\u00edctima tr\u00e1gica a l\u00edder despiadada con decisiones cada vez m\u00e1s oscuras."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad m\u00e1gica flotante est\u00e1 asociada al Kirin Tor?",o:["Dalaran", "Shattrath", "Gilneas", "Theramore"],a:0,exp:"Dalaran es la ciudad de los magos del Kirin Tor y ha tenido un papel central en varias expansiones.",extra:"Dalaran ha servido como ciudad neutral y centro de operaciones en momentos clave, especialmente durante Wrath of the Lich King y Legion."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de World of Warcraft introdujo Pandaria?",o:["Cataclysm", "Mists of Pandaria", "Warlords of Draenor", "Battle for Azeroth"],a:1,exp:"Mists of Pandaria introdujo el continente de Pandaria y la raza pandaren como jugable.",extra:"Aunque al principio fue recibida con dudas por algunos jugadores, la expansi\u00f3n gan\u00f3 reconocimiento por su ambientaci\u00f3n, m\u00fasica, zonas y temas sobre guerra, equilibrio y corrupci\u00f3n emocional."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n llev\u00f3 a los jugadores a una versi\u00f3n alternativa de Draenor?",o:["Legion", "Warlords of Draenor", "Shadowlands", "Dragonflight"],a:1,exp:"Warlords of Draenor presenta una l\u00ednea temporal alternativa de Draenor antes de convertirse en Terrallende.",extra:"La expansi\u00f3n permiti\u00f3 ver a l\u00edderes orcos legendarios como Grommash, Blackhand, Ner zhul y Kilrogg en un contexto distinto al de la historia principal."},
  {t:"m",q:"\u00bfCu\u00e1l es el demonio mayor considerado l\u00edder original de la Legi\u00f3n Ardiente?",o:["Sargeras", "Mannoroth", "Archimonde", "Kil jaeden"],a:0,exp:"Sargeras es el tit\u00e1n ca\u00eddo que crea y lidera la Legi\u00f3n Ardiente.",extra:"Su ca\u00edda nace del miedo a la corrupci\u00f3n del Vac\u00edo. En el lore de Warcraft, Sargeras no se ve a s\u00ed mismo simplemente como malvado, sino como alguien dispuesto a destruir la creaci\u00f3n para evitar algo peor."},
  {t:"m",q:"\u00bfCu\u00e1l es el nombre del mundo principal donde ocurren la mayor\u00eda de historias de Warcraft?",o:["Santuario", "Aiur", "Azeroth", "Korhal"],a:2,exp:"Azeroth es el mundo principal de Warcraft y escenario central de la mayor\u00eda de sus conflictos.",extra:"Azeroth no es solo un planeta, sino tambi\u00e9n una entidad tit\u00e1nica dormida, algo que gana importancia en expansiones posteriores del lore."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Blizzard populariz\u00f3 la frase \u201cYou must construct additional pylons\u201d?",o:["Warcraft III", "StarCraft", "Diablo II", "Overwatch"],a:1,exp:"La frase aparece en StarCraft cuando el jugador protoss intenta crear unidades sin suficiente suministro de pylons.",extra:"Se convirti\u00f3 en uno de los memes m\u00e1s famosos de Blizzard porque resume de forma perfecta la frustraci\u00f3n de quedarse sin capacidad de poblaci\u00f3n en medio de una partida."},
  {t:"m",q:"\u00bfCu\u00e1l es el mundo donde ocurre principalmente la saga Diablo?",o:["Azeroth", "Santuario", "Aiur", "Terrallende"],a:1,exp:"La saga Diablo transcurre principalmente en Santuario, un mundo creado como refugio entre \u00e1ngeles y demonios.",extra:"Santuario fue creado por Inarius y Lilith como un lugar apartado del Conflicto Eterno. Sus habitantes humanos descienden de la uni\u00f3n entre \u00e1ngeles y demonios."},
  {t:"m",q:"\u00bfQui\u00e9n es el Se\u00f1or del Terror que da nombre a la saga Diablo?",o:["Mephisto", "Baal", "Diablo", "Azmodan"],a:2,exp:"Diablo es el Se\u00f1or del Terror y uno de los tres Males Supremos.",extra:"Diablo representa el miedo como fuerza corruptora. A lo largo de la saga, manipula cuerpos, almas e instituciones para regresar una y otra vez."},
  {t:"m",q:"\u00bfQui\u00e9nes son los tres Males Supremos en Diablo?",o:["Diablo, Baal y Mephisto", "Azmodan, Belial y Duriel", "Andariel, Lilith y Inarius", "Tyrael, Imperius y Malthael"],a:0,exp:"Los tres Males Supremos son Diablo, Baal y Mephisto.",extra:"Cada uno representa una forma mayor de corrupci\u00f3n demon\u00edaca: terror, destrucci\u00f3n y odio. Su influencia define gran parte del conflicto central de los primeros juegos."},
  {t:"m",q:"\u00bfQu\u00e9 objeto se usa para contener la esencia de demonios poderosos en Diablo?",o:["Piedra del Mundo", "Piedra de Alma", "Cubo Hor\u00e1drico", "Llave Infernal"],a:1,exp:"Las Piedras de Alma se usan para encerrar la esencia de los Males Supremos y otros demonios poderosos.",extra:"El problema es que estas piedras tambi\u00e9n pueden corromper a quienes las usan o transportan. En Diablo, casi toda soluci\u00f3n m\u00e1gica importante tiene un coste terrible."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad sirve como punto inicial en Diablo II?",o:["Tristram", "Lut Gholein", "Harrogath", "Campamento de las Arp\u00edas"],a:3,exp:"Diablo II comienza en el Campamento de las Arp\u00edas, desde donde el jugador investiga la corrupci\u00f3n que se extiende por la regi\u00f3n.",extra:"Aunque Tristram es central para el origen de la saga, Diablo II arranca con las Arp\u00edas, los ca\u00eddos, Andariel y la b\u00fasqueda del Caminante Oscuro."},
  {t:"m",q:"\u00bfQu\u00e9 demonio es el jefe final del Acto I en Diablo II?",o:["Duriel", "Andariel", "Mephisto", "Baal"],a:1,exp:"Andariel, la Doncella de la Angustia, es la jefa final del Acto I de Diablo II.",extra:"Su presencia en el monasterio marca el avance de la corrupci\u00f3n demon\u00edaca y el peligro que sigue al paso del Caminante Oscuro."},
  {t:"m",q:"\u00bfQu\u00e9 jefe espera al jugador al final del Acto II de Diablo II?",o:["Duriel", "Baal", "Belial", "Azmodan"],a:0,exp:"Duriel, el Se\u00f1or del Dolor, es el jefe final del Acto II.",extra:"Duriel es recordado por muchos jugadores como una pelea brutal, especialmente en primeras partidas, por su velocidad, da\u00f1o y el espacio cerrado de la c\u00e1mara."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo II usa invocaciones como esqueletos y g\u00f3lems?",o:["Palad\u00edn", "Hechicera", "Nigromante", "Amazona"],a:2,exp:"El Nigromante puede invocar esqueletos, g\u00f3lems y usar maldiciones para controlar el campo de batalla.",extra:"El Nigromante es una de las clases m\u00e1s emblem\u00e1ticas de Diablo II porque permite jugar como comandante de un ej\u00e9rcito de muertos vivientes."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de Diablo II a\u00f1ade el Acto V y la clase Asesina y Druida?",o:["Reaper of Souls", "Lord of Destruction", "Hellfire", "Rise of the Necromancer"],a:1,exp:"Diablo II: Lord of Destruction a\u00f1ade el Acto V, adem\u00e1s de las clases Asesina y Druida.",extra:"La expansi\u00f3n ampli\u00f3 enormemente el juego con runas, objetos nuevos, enemigos y la confrontaci\u00f3n final contra Baal en el Monte Arreat."},
  {t:"m",q:"\u00bfQui\u00e9n es el arc\u00e1ngel que ayuda repetidamente a la humanidad en Diablo?",o:["Imperius", "Tyrael", "Malthael", "Auriel"],a:1,exp:"Tyrael es el arc\u00e1ngel de la Justicia y uno de los mayores aliados de la humanidad.",extra:"Tyrael desaf\u00eda al Cielo cuando considera que la humanidad merece una oportunidad. Su relaci\u00f3n con los mortales es uno de los ejes morales de Diablo."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de Diablo III tiene como antagonista principal a Malthael?",o:["Lord of Destruction", "Reaper of Souls", "Rise of the Necromancer", "Vessel of Hatred"],a:1,exp:"Reaper of Souls presenta a Malthael, el antiguo arc\u00e1ngel de la Sabidur\u00eda convertido en \u00c1ngel de la Muerte.",extra:"Malthael no busca servir al Infierno, sino eliminar toda corrupci\u00f3n demon\u00edaca, incluyendo la que existe dentro de la humanidad. Esa l\u00f3gica lo convierte en una amenaza apocal\u00edptica."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo III utiliza furia como recurso principal?",o:["Mago", "B\u00e1rbaro", "Cazador de demonios", "Monje"],a:1,exp:"El B\u00e1rbaro usa furia como recurso, gener\u00e1ndola en combate y gast\u00e1ndola en habilidades poderosas.",extra:"El B\u00e1rbaro representa fuerza f\u00edsica, resistencia y combate directo. Es heredero espiritual de la clase b\u00e1rbara de Diablo II."},
  {t:"m",q:"\u00bfQui\u00e9n es la madre de Santuario en el lore de Diablo IV?",o:["Auriel", "Adria", "Lilith", "Andariel"],a:2,exp:"Lilith es considerada la madre de Santuario, creado junto a Inarius como refugio del Conflicto Eterno.",extra:"En Diablo IV, Lilith regresa como una figura ambigua: monstruosa y manipuladora, pero tambi\u00e9n ligada al origen mismo de la humanidad."},
  {t:"m",q:"\u00bfQui\u00e9n es Inarius dentro del lore de Diablo?",o:["Un demonio menor", "Un arc\u00e1ngel relacionado con la creaci\u00f3n de Santuario", "Un rey humano de Khanduras", "Un nigromante hor\u00e1drico"],a:1,exp:"Inarius es un \u00e1ngel que participa en la creaci\u00f3n de Santuario junto a Lilith.",extra:"Su historia es tr\u00e1gica y contradictoria: busca escapar del Conflicto Eterno, pero termina obsesionado con control, castigo y redenci\u00f3n personal."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n antigua se dedica a combatir y contener los males demon\u00edacos en Diablo?",o:["La Mano de Plata", "Los Hor\u00e1drim", "El Kirin Tor", "Los Templarios Oscuros"],a:1,exp:"Los Hor\u00e1drim son una orden de magos y sabios creada para enfrentar a los Males Supremos.",extra:"Los Hor\u00e1drim aparecen una y otra vez en la saga como guardianes de conocimiento peligroso. Deckard Cain es su representante m\u00e1s querido por los fans."},
  {t:"m",q:"\u00bfQui\u00e9n es Deckard Cain?",o:["Un rey de Tristram", "Un miembro de los Hor\u00e1drim y gu\u00eda del jugador", "Un demonio disfrazado", "Un arc\u00e1ngel ca\u00eddo"],a:1,exp:"Deckard Cain es un sabio Hor\u00e1drico que gu\u00eda al jugador con conocimiento sobre demonios, objetos e historia.",extra:"Su frase invitando a quedarse y escuchar es una de las l\u00edneas m\u00e1s famosas de Blizzard. Cain funciona como puente entre el jugador y el lore profundo de Diablo."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo suele estar asociada a arcos, trampas y caza de demonios?",o:["Cazador de demonios", "Cruzado", "B\u00e1rbaro", "Druida"],a:0,exp:"El Cazador de demonios usa armas a distancia, trampas y t\u00e9cnicas de venganza contra criaturas infernales.",extra:"En Diablo III, esta clase mezcla agilidad, odio, disciplina y una est\u00e9tica oscura de cazador obsesionado con destruir demonios."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Blizzard pertenece al g\u00e9nero RTS y enfrenta tres razas asim\u00e9tricas?",o:["Diablo III", "StarCraft", "World of Warcraft", "Hearthstone"],a:1,exp:"StarCraft es un RTS construido alrededor de tres razas muy distintas: terran, zerg y protoss.",extra:"Su dise\u00f1o asim\u00e9trico es una de las razones de su longevidad competitiva. Cada raza tiene econom\u00eda, unidades, ritmo y estilo estrat\u00e9gico propios."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Blizzard tiene como conflicto central el enfrentamiento entre el Cielo, el Infierno y la humanidad?",o:["Warcraft", "StarCraft", "Diablo", "Lost Vikings"],a:2,exp:"Diablo gira alrededor del Conflicto Eterno entre \u00e1ngeles y demonios, con la humanidad atrapada en medio.",extra:"La saga funciona porque los humanos no son simples v\u00edctimas: por su origen mixto, tienen un potencial que tanto el Cielo como el Infierno temen o desean controlar."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Blizzard tiene a la Alianza y la Horda como facciones principales?",o:["Diablo", "Warcraft", "StarCraft", "Heroes of the Storm"],a:1,exp:"Warcraft tiene como eje hist\u00f3rico el conflicto, alianza temporal y rivalidad entre la Alianza y la Horda.",extra:"Aunque empez\u00f3 como una guerra entre humanos y orcos, con el tiempo Warcraft convirti\u00f3 ambos bandos en coaliciones complejas con culturas, l\u00edderes y conflictos internos."},
  {t:"m",q:"\u00bfQu\u00e9 personaje conecta fuertemente Warcraft III con World of Warcraft por su ca\u00edda y regreso como jefe final de expansi\u00f3n?",o:["Arthas Menethil", "Jim Raynor", "Deckard Cain", "Tyrael"],a:0,exp:"Arthas pasa de protagonista tr\u00e1gico en Warcraft III a gran amenaza en Wrath of the Lich King.",extra:"Su arco es uno de los ejemplos m\u00e1s claros de c\u00f3mo Blizzard traslad\u00f3 una historia de estrategia en tiempo real a una experiencia MMO con raids y progresi\u00f3n comunitaria."},
  {t:"m",q:"\u00bfQu\u00e9 unidad terran puede reparar unidades mec\u00e1nicas y edificios en StarCraft?",o:["Marine", "SCV", "M\u00e9dico", "Fantasma"],a:1,exp:"El SCV es la unidad obrera terran y puede recolectar recursos, construir edificios y reparar estructuras o unidades mec\u00e1nicas.",extra:"El SCV es una pieza clave de la identidad terran: a diferencia de los drones zerg o sondas protoss, permanece construyendo el edificio hasta terminarlo y adem\u00e1s puede reparar, algo vital en defensas, tanques, bunkers y cruceros de batalla."},
  {t:"m",q:"\u00bfQu\u00e9 unidad protoss puede transportar tropas y usar habilidades de apoyo en StarCraft II?",o:["Carrier", "Warp Prism", "Observer", "Phoenix"],a:1,exp:"El Warp Prism puede transportar unidades protoss y tambi\u00e9n desplegar un campo de energ\u00eda para invocar tropas mediante warpgates.",extra:"El Warp Prism es una de las unidades m\u00e1s importantes del juego competitivo protoss. Permite ataques sorpresa, refuerzos r\u00e1pidos y microgesti\u00f3n agresiva en la base enemiga."},
  {t:"m",q:"\u00bfQu\u00e9 edificio zerg produce larvas para crear unidades?",o:["Spawning Pool", "Hatchery", "Evolution Chamber", "Hydralisk Den"],a:1,exp:"La Hatchery es el edificio central zerg y genera larvas, que luego se transforman en drones, unidades militares o overlords.",extra:"La mec\u00e1nica de larvas es lo que diferencia radicalmente a los zerg de terran y protoss. En lugar de producir cada unidad desde edificios separados, los zerg convierten larvas en casi cualquier unidad disponible."},
  {t:"m",q:"\u00bfQu\u00e9 personaje terran es conocido por pilotar el crucero de batalla Hyperion?",o:["Edmund Duke", "Matt Horner", "Gabriel Tosh", "Valerian Mengsk"],a:1,exp:"Matt Horner es el capit\u00e1n del Hyperion y uno de los aliados m\u00e1s confiables de Jim Raynor.",extra:"Horner representa el lado m\u00e1s disciplinado y honorable de los Raiders de Raynor. Mientras Raynor suele actuar desde la emoci\u00f3n y la culpa, Horner mantiene la operaci\u00f3n funcionando con calma militar."},
  {t:"m",q:"\u00bfQu\u00e9 unidad terran puede lanzar armas nucleares si tiene un silo preparado?",o:["Marauder", "Ghost", "Siege Tank", "Viking"],a:1,exp:"El Ghost puede marcar objetivos para ataques nucleares terran, siempre que el jugador haya preparado un misil nuclear.",extra:"El anuncio de \u201cnuclear launch detected\u201d es una de las frases m\u00e1s tensas de StarCraft. Obliga al rival a encontrar r\u00e1pidamente al Ghost antes de que el misil destruya trabajadores, ej\u00e9rcito o estructuras clave."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la organizaci\u00f3n secreta terran especializada en fantasmas y operaciones encubiertas?",o:["Dominion Navy", "Ghost Program", "Moebius Foundation", "Umojan Protectorate"],a:1,exp:"El programa Ghost entrena ps\u00edquicos terran para convertirlos en agentes de infiltraci\u00f3n, sabotaje y asesinato.",extra:"Personajes como Sarah Kerrigan y Nova Terra vienen de ese contexto. El programa Ghost muestra el lado m\u00e1s oscuro de los gobiernos terran: manipulaci\u00f3n mental, control y uso militar de personas con habilidades psi\u00f3nicas."},
  {t:"m",q:"\u00bfQu\u00e9 unidad a\u00e9rea zerg es famosa por atacar rebotando entre varios objetivos?",o:["Mutalisk", "Corruptor", "Brood Lord", "Viper"],a:0,exp:"El Mutalisk lanza ataques que rebotan entre varios objetivos cercanos, haci\u00e9ndolo peligroso contra trabajadores y unidades agrupadas.",extra:"El mutalisk ha sido hist\u00f3ricamente una unidad de hostigamiento. Su fuerza est\u00e1 en la movilidad, el da\u00f1o acumulativo y la capacidad de obligar al rival a defender m\u00faltiples puntos."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe protoss se sacrifica para destruir a la Supermente en StarCraft?",o:["Artanis", "Tassadar", "Zeratul", "Aldaris"],a:1,exp:"Tassadar se sacrifica canalizando energ\u00edas templarias y oscuras para destruir a la Supermente zerg.",extra:"El sacrificio de Tassadar es uno de los momentos m\u00e1s importantes del StarCraft original. Tambi\u00e9n simboliza la uni\u00f3n entre templarios khalai y templarios oscuros, dos ramas protoss hist\u00f3ricamente separadas."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n protoss rechaza el Khala y vive separada de Aiur?",o:["Taldarim", "Purificadores", "Templarios oscuros", "Ejecutores"],a:2,exp:"Los templarios oscuros rechazan el Khala y viven separados del resto de la sociedad protoss tradicional.",extra:"Los Nerazim, o templarios oscuros, fueron exiliados por negarse a unirse al Khala. Su cultura gira alrededor de la independencia psi\u00f3nica, el sigilo y una visi\u00f3n distinta del destino protoss."},
  {t:"m",q:"\u00bfQu\u00e9 planeta volc\u00e1nico es considerado el mundo central de los zerg?",o:["Char", "Aiur", "Korhal", "Mar Sara"],a:0,exp:"Char es el mundo volc\u00e1nico donde el Enjambre zerg establece una de sus bases principales.",extra:"Char es hostil, abrasador y casi inhabitable para humanos normales, pero perfecto para los zerg. All\u00ed ocurren varios de los eventos m\u00e1s importantes de la saga, incluyendo enfrentamientos con Kerrigan."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de StarCraft II lidera la Fundaci\u00f3n Moebius antes de revelarse su conexi\u00f3n con Amon?",o:["Emil Narud", "Valerian Mengsk", "Gabriel Tosh", "Stetmann"],a:0,exp:"Emil Narud dirige la Fundaci\u00f3n Moebius y m\u00e1s tarde se revela como un sirviente de Amon.",extra:"Narud es un ejemplo cl\u00e1sico de villano infiltrado en la ciencia y la investigaci\u00f3n. La Fundaci\u00f3n Moebius parec\u00eda buscar conocimiento, pero estaba vinculada a planes mucho m\u00e1s oscuros."},
  {t:"m",q:"\u00bfQu\u00e9 unidad protoss invisible sirve principalmente para exploraci\u00f3n?",o:["Observer", "Colossus", "Immortal", "Sentry"],a:0,exp:"El Observer es una unidad invisible de detecci\u00f3n y exploraci\u00f3n usada por los protoss.",extra:"Aunque no ataca, el Observer es vital para detectar unidades invisibles o enterradas. En StarCraft, la informaci\u00f3n suele valer tanto como el ej\u00e9rcito."},
  {t:"m",q:"\u00bfQu\u00e9 unidad terran puede cambiar entre modo a\u00e9reo y modo terrestre en StarCraft II?",o:["Viking", "Banshee", "Raven", "Medivac"],a:0,exp:"El Viking puede operar como caza a\u00e9reo o aterrizar para atacar objetivos terrestres.",extra:"Su flexibilidad lo hace \u00fatil contra unidades a\u00e9reas grandes como colosos, se\u00f1ores de la prole o cruceros de batalla, dependiendo de la composici\u00f3n enemiga."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de StarCraft es un antiguo compa\u00f1ero de prisi\u00f3n de Jim Raynor?",o:["Tychus Findlay", "Arcturus Mengsk", "Samir Duran", "Gerard DuGalle"],a:0,exp:"Tychus Findlay es un viejo compa\u00f1ero de Raynor y aparece en Wings of Liberty con una agenda oculta.",extra:"Tychus tiene una presencia enorme en la campa\u00f1a terran de StarCraft II. Su amistad con Raynor est\u00e1 marcada por lealtad, cinismo, deuda y manipulaci\u00f3n pol\u00edtica."},
  {t:"m",q:"\u00bfQu\u00e9 unidad zerg puede enterrarse y atacar desde debajo de la tierra?",o:["Roach", "Lurker", "Queen", "Baneling"],a:1,exp:"El Lurker se entierra y ataca con espinas subterr\u00e1neas que da\u00f1an l\u00edneas de unidades enemigas.",extra:"Introducido en Brood War, el Lurker cambi\u00f3 mucho el juego zerg. Obliga al rival a tener detecci\u00f3n y a respetar posiciones defensivas zerg muy peligrosas."},
  {t:"m",q:"\u00bfQu\u00e9 reino humano es destruido por la Plaga durante la historia de Arthas?",o:["Kul Tiras", "Lordaeron", "Gilneas", "Alterac"],a:1,exp:"Lordaeron cae por la Plaga y por la corrupci\u00f3n de Arthas, que termina asesinando a su propio padre.",extra:"La ca\u00edda de Lordaeron es una de las tragedias centrales de Warcraft III. Marca el nacimiento de los no-muertos como fuerza dominante y el punto de quiebre definitivo de Arthas."},
  {t:"m",q:"\u00bfQui\u00e9n fue el mentor palad\u00edn de Arthas?",o:["Tirion Fordring", "Uther el Iluminado", "Bolvar Fordragon", "Turalyon"],a:1,exp:"Uther el Iluminado fue mentor de Arthas y uno de los paladines m\u00e1s importantes de la Mano de Plata.",extra:"La relaci\u00f3n entre Uther y Arthas es tr\u00e1gica porque Uther ve c\u00f3mo su alumno abandona los principios de la Luz. Su muerte a manos de Arthas refuerza la dimensi\u00f3n personal de esa ca\u00edda."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad ordena Arthas purgar para detener la Plaga?",o:["Dalaran", "Stratholme", "Theramore", "Andorhal"],a:1,exp:"Arthas ordena la purga de Stratholme al descubrir que sus ciudadanos estaban infectados por grano contaminado.",extra:"Stratholme es uno de los momentos morales m\u00e1s famosos de Warcraft. La decisi\u00f3n de Arthas puede entenderse militarmente, pero tambi\u00e9n muestra su disposici\u00f3n a cruzar l\u00edmites irreversibles."},
  {t:"m",q:"\u00bfQu\u00e9 personaje lidera a los elfos de la noche junto a Malfurion?",o:["Tyrande Whisperwind", "Jaina Proudmoore", "Valeera Sanguinar", "Maiev Shadowsong"],a:0,exp:"Tyrande Whisperwind es suma sacerdotisa de Elune y una de las l\u00edderes principales de los elfos de la noche.",extra:"Tyrande combina liderazgo espiritual, poder marcial y una relaci\u00f3n central con Malfurion e Illidan. Su papel atraviesa miles de a\u00f1os de historia kaldorei."},
  {t:"m",q:"\u00bfQu\u00e9 guardiana persigue obsesivamente a Illidan Stormrage?",o:["Shandris Feathermoon", "Maiev Shadowsong", "Alleria Windrunner", "Ysera"],a:1,exp:"Maiev Shadowsong es la guardiana encargada de custodiar a Illidan y luego perseguirlo tras su escape.",extra:"Maiev es uno de los personajes m\u00e1s intensos de Warcraft. Su deber se transforma poco a poco en obsesi\u00f3n, haciendo que su relaci\u00f3n con Illidan sea m\u00e1s compleja que una simple persecuci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad-estado humana es liderada por Jaina Proudmoore tras Warcraft III?",o:["Theramore", "Lordaeron", "Gilneas", "Dalaran"],a:0,exp:"Jaina funda y lidera Theramore como refugio humano en Kalimdor.",extra:"Theramore representa el intento de Jaina de construir paz entre facciones. Su destrucci\u00f3n posterior cambia profundamente su car\u00e1cter y su visi\u00f3n sobre la Horda."},
  {t:"m",q:"\u00bfQu\u00e9 orco mata a Mannoroth y libera a los orcos de la maldici\u00f3n demon\u00edaca?",o:["Thrall", "Grommash Hellscream", "Orgrim Doomhammer", "Durotan"],a:1,exp:"Grommash Hellscream mata a Mannoroth, sacrific\u00e1ndose para liberar a los orcos de la corrupci\u00f3n demon\u00edaca.",extra:"El momento es crucial para la identidad moderna de la Horda. Grommash, que hab\u00eda bebido la sangre demon\u00edaca, termina pagando con su vida para romper esa cadena."},
  {t:"m",q:"\u00bfQu\u00e9 raza de Warcraft fue exiliada de Argus y lleg\u00f3 a Azeroth huyendo de la Legi\u00f3n?",o:["Draenei", "Tauren", "Pandaren", "Gnomos"],a:0,exp:"Los draenei son eredars que huyeron de Argus tras rechazar la corrupci\u00f3n de Sargeras.",extra:"Liderados por Velen, los draenei representan fe, exilio y resistencia. Su historia conecta directamente Azeroth con la escala c\u00f3smica de la Legi\u00f3n Ardiente."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00edder espiritual gu\u00eda a los draenei?",o:["Velen", "Prophet Zul", "Akama", "Maraad"],a:0,exp:"Velen, conocido como el Profeta, lidera a los draenei y posee visiones del futuro.",extra:"Velen es uno de los personajes m\u00e1s antiguos y pacientes del lore de Warcraft. Su conflicto con Kil jaeden y Archimonde viene de la ca\u00edda original de los eredar."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de World of Warcraft introdujo a los cazadores de demonios como clase jugable?",o:["The Burning Crusade", "Legion", "Shadowlands", "Dragonflight"],a:1,exp:"Legion introdujo a los cazadores de demonios como clase jugable, vinculados directamente a Illidan.",extra:"Los cazadores de demonios sacrifican parte de s\u00ed mismos para combatir a la Legi\u00f3n con su propio poder. Su est\u00e9tica, movilidad y doble salto los hicieron muy distintivos dentro de WoW."},
  {t:"m",q:"\u00bfQu\u00e9 arma legendaria est\u00e1 asociada a Tirion Fordring en Wrath of the Lich King?",o:["Frostmourne", "Ashbringer", "Doomhammer", "Thunderfury"],a:1,exp:"Ashbringer es la espada legendaria que porta Tirion Fordring durante la lucha contra el Rey Ex\u00e1nime.",extra:"Ashbringer es una de las armas m\u00e1s ic\u00f3nicas de Warcraft. Su historia est\u00e1 ligada a la Luz, la corrupci\u00f3n, la redenci\u00f3n y la ca\u00edda de la Plaga."},
  {t:"m",q:"\u00bfQui\u00e9n se convierte en Rey Ex\u00e1nime despu\u00e9s de la derrota de Arthas?",o:["Tirion Fordring", "Bolvar Fordragon", "Darion Mograine", "Varian Wrynn"],a:1,exp:"Bolvar Fordragon toma el yelmo del Rey Ex\u00e1nime para contener a la Plaga tras la muerte de Arthas.",extra:"La idea era que siempre deb\u00eda existir un Rey Ex\u00e1nime para controlar a los no-muertos. Bolvar acepta ese destino como sacrificio silencioso."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad de los elfos de sangre funciona como su capital?",o:["Darnassus", "Lunargenta", "Suramar", "Quel Danas"],a:1,exp:"Lunargenta es la capital de los elfos de sangre en Quel Thalas.",extra:"Silvermoon o Lunargenta conserva una est\u00e9tica elegante y arcana, marcada por la tragedia de la invasi\u00f3n de la Plaga y la dependencia posterior de fuentes m\u00e1gicas."},
  {t:"m",q:"\u00bfQu\u00e9 fuente de poder arcano era central para los altos elfos y luego los elfos de sangre?",o:["Pozo de la Eternidad", "Fuente del Sol", "Alma de Drag\u00f3n", "Ojo de Sargeras"],a:1,exp:"La Fuente del Sol era la fuente m\u00e1gica central de Quel Thalas y de la sociedad \u00e9lfica de sangre.",extra:"Su corrupci\u00f3n y restauraci\u00f3n son eventos fundamentales para entender la identidad de los elfos de sangre, su adicci\u00f3n m\u00e1gica y su transformaci\u00f3n pol\u00edtica."},
  {t:"m",q:"\u00bfQu\u00e9 jefe de banda de World of Warcraft pronuncia la famosa frase \u201c\u00a1No est\u00e1is preparados!\u201d?",o:["Arthas", "Illidan Stormrage", "Deathwing", "Ragnaros"],a:1,exp:"Illidan Stormrage pronuncia esa frase como advertencia desafiante en The Burning Crusade.",extra:"La frase se volvi\u00f3 una de las l\u00edneas m\u00e1s famosas de Blizzard. Resume perfectamente la mezcla de arrogancia, amenaza y dramatismo que define a Illidan."},
  {t:"m",q:"\u00bfQu\u00e9 Se\u00f1or Elemental es jefe final del N\u00facleo de Magma?",o:["Al Akir", "Ragnaros", "Neptulon", "Therazane"],a:1,exp:"Ragnaros, el Se\u00f1or del Fuego, es el jefe final de Molten Core o N\u00facleo de Magma.",extra:"Ragnaros fue uno de los primeros grandes jefes ic\u00f3nicos de World of Warcraft. Para muchos jugadores veteranos, derrotarlo marc\u00f3 el inicio real de las raids \u00e9picas."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n negro manipula la pol\u00edtica de Ventormenta bajo una identidad humana?",o:["Onyxia", "Sintharia", "Ysera", "Alexstrasza"],a:0,exp:"Onyxia se infiltra en Ventormenta bajo la identidad de Lady Katrana Prestor.",extra:"La manipulaci\u00f3n de Onyxia muestra el talento de los dragones negros para la intriga pol\u00edtica. No solo amenazan con fuego y garras, tambi\u00e9n con corrupci\u00f3n institucional."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Diablo pronuncia la famosa invitaci\u00f3n \u201cStay awhile and listen\u201d?",o:["Tyrael", "Deckard Cain", "Marius", "Lorath Nahr"],a:1,exp:"Deckard Cain es quien invita al jugador a quedarse y escuchar, convirtiendo la frase en un s\u00edmbolo de la saga.",extra:"Cain es m\u00e1s que un identificador de objetos: funciona como narrador, historiador y figura de confianza en un mundo donde casi todo est\u00e1 corrupto o condenado."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo II usa auras como parte central de su estilo de juego?",o:["Palad\u00edn", "Nigromante", "Asesina", "Hechicera"],a:0,exp:"El Palad\u00edn usa auras ofensivas y defensivas que afectan tanto a \u00e9l como a aliados cercanos.",extra:"Las auras del Palad\u00edn lo convierten en una clase muy vers\u00e1til. Puede especializarse en combate cuerpo a cuerpo, apoyo grupal o configuraciones famosas como el Hammerdin."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo II se especializa en artes marciales, trampas y disciplinas sombr\u00edas?",o:["Amazona", "Asesina", "Druida", "Hechicera"],a:1,exp:"La Asesina, a\u00f1adida en Lord of Destruction, combina artes marciales, trampas y habilidades de sombra.",extra:"La Asesina pertenece a una orden entrenada para combatir magos corruptos. Su dise\u00f1o mezcla velocidad, t\u00e9cnica y herramientas t\u00e1cticas poco comunes en otras clases."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo II puede transformarse en hombre lobo u hombre oso?",o:["Druida", "Palad\u00edn", "B\u00e1rbaro", "Nigromante"],a:0,exp:"El Druida puede usar metamorfosis para convertirse en hombre lobo u hombre oso.",extra:"El Druida combina magia elemental, invocaciones naturales y transformaci\u00f3n f\u00edsica. Su identidad est\u00e1 muy conectada con la naturaleza salvaje y los pueblos del norte."},
  {t:"m",q:"\u00bfQu\u00e9 demonio de Diablo II es el Se\u00f1or del Odio?",o:["Diablo", "Baal", "Mephisto", "Duriel"],a:2,exp:"Mephisto es el Se\u00f1or del Odio y uno de los tres Males Supremos.",extra:"Mephisto es el primero de los Males Supremos que el jugador enfrenta directamente en Diablo II. Su influencia corrompe Kurast y al consejo de Zakarum."},
  {t:"m",q:"\u00bfQu\u00e9 demonio de Diablo II es el Se\u00f1or de la Destrucci\u00f3n?",o:["Baal", "Diablo", "Mephisto", "Azmodan"],a:0,exp:"Baal es el Se\u00f1or de la Destrucci\u00f3n y antagonista principal de Lord of Destruction.",extra:"Baal busca corromper la Piedra del Mundo en el Monte Arreat. Su campa\u00f1a amenaza la estructura misma de Santuario."},
  {t:"m",q:"\u00bfQu\u00e9 artefacto de Diablo II permite combinar objetos y realizar recetas?",o:["Cubo Hor\u00e1drico", "Piedra de Alma", "Piedra del Mundo", "Libro de Ca\u00edn"],a:0,exp:"El Cubo Hor\u00e1drico permite transmutar objetos, crear recetas y avanzar en misiones clave.",extra:"El Cubo Hor\u00e1drico es uno de los objetos m\u00e1s queridos de Diablo II por su utilidad pr\u00e1ctica y por su conexi\u00f3n con los Hor\u00e1drim."},
  {t:"m",q:"\u00bfQu\u00e9 lugar bajo la catedral de Tristram es central en el primer Diablo?",o:["El Monasterio", "Las catacumbas y el infierno bajo la catedral", "El Monte Arreat", "La Fortaleza del Pandem\u00f3nium"],a:1,exp:"El primer Diablo se desarrolla descendiendo por la catedral de Tristram hasta llegar al Infierno.",extra:"La estructura descendente del primer Diablo es simple pero poderosa: cada nivel baja m\u00e1s en corrupci\u00f3n, horror y peligro hasta el enfrentamiento final con Diablo."},
  {t:"m",q:"\u00bfQui\u00e9n es el pr\u00edncipe pose\u00eddo por Diablo en el primer juego?",o:["Albrecht", "Lachdanan", "Leoric", "Marius"],a:0,exp:"Albrecht, hijo del rey Leoric, es pose\u00eddo por Diablo bajo la catedral de Tristram.",extra:"La posesi\u00f3n de Albrecht es el n\u00facleo tr\u00e1gico del primer Diablo. La corrupci\u00f3n destruye a una familia real, una ciudad y finalmente arrastra al h\u00e9roe hacia un destino oscuro."},
  {t:"m",q:"\u00bfC\u00f3mo se conoce al rey de Khanduras corrompido por la influencia de Diablo?",o:["Rey Leoric", "Rey Wrynn", "Rey Terenas", "Rey Anu"],a:0,exp:"El rey Leoric, conocido como el Rey Esqueleto, cae en la locura por la influencia de Diablo.",extra:"Leoric es uno de los primeros grandes s\u00edmbolos de la corrupci\u00f3n demon\u00edaca en Diablo. Su tragedia muestra que Diablo destruye tanto por posesi\u00f3n directa como por manipulaci\u00f3n mental."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Diablo II narra buena parte de las cinem\u00e1ticas siguiendo al Caminante Oscuro?",o:["Marius", "Deckard Cain", "Tyrael", "Warriv"],a:0,exp:"Marius narra su experiencia siguiendo al Caminante Oscuro, sin comprender del todo la magnitud de lo que presencia.",extra:"Marius funciona como testigo humano del horror. No es un h\u00e9roe poderoso, sino una persona com\u00fan arrastrada por fuerzas que lo superan completamente."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo III usa mantras y combate marcial sagrado?",o:["Monje", "B\u00e1rbaro", "M\u00e9dico brujo", "Cruzado"],a:0,exp:"El Monje combina artes marciales, mantras y poder espiritual para combatir demonios.",extra:"El Monje de Diablo III destaca por su movilidad y ritmo de combate. Su fantas\u00eda es la de un guerrero disciplinado que canaliza fuerza interior contra el Infierno."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo III invoca fetiches, plagas y criaturas espirituales?",o:["M\u00e9dico brujo", "Mago", "Cruzado", "Cazador de demonios"],a:0,exp:"El M\u00e9dico brujo utiliza magia espiritual, venenos, invocaciones y criaturas extra\u00f1as para controlar la batalla.",extra:"Es una de las clases con identidad visual m\u00e1s peculiar de Diablo III. Mezcla humor oscuro, horror tribal y control de masas."},
  {t:"m",q:"\u00bfQu\u00e9 clase de Diablo III contin\u00faa la fantas\u00eda del palad\u00edn con escudo, fe y armadura pesada?",o:["Cruzado", "Monje", "B\u00e1rbaro", "Nigromante"],a:0,exp:"El Cruzado, a\u00f1adido en Reaper of Souls, hereda parte de la fantas\u00eda del palad\u00edn: armadura pesada, escudo y poder sagrado.",extra:"El Cruzado representa una orden marcial religiosa dedicada a purgar la corrupci\u00f3n. Sus habilidades combinan defensa, golpes contundentes y magia de la Luz."},
  {t:"m",q:"\u00bfQu\u00e9 \u00e1ngel de Diablo III representa el Valor y suele desconfiar de la humanidad?",o:["Imperius", "Tyrael", "Auriel", "Itherael"],a:0,exp:"Imperius es el Arc\u00e1ngel del Valor y frecuentemente se muestra hostil o desconfiado hacia los humanos.",extra:"Imperius no es simplemente malvado: representa una visi\u00f3n r\u00edgida del deber celestial. Para \u00e9l, la humanidad es peligrosa por su herencia demon\u00edaca."},
  {t:"m",q:"\u00bfQu\u00e9 \u00e1ngel de Diablo III representa la Esperanza?",o:["Auriel", "Malthael", "Imperius", "Tyrael"],a:0,exp:"Auriel es el Arc\u00e1ngel de la Esperanza dentro del Consejo de Angiris.",extra:"Auriel equilibra el tono sombr\u00edo del universo Diablo. Su existencia simboliza que incluso en un mundo dominado por corrupci\u00f3n y p\u00e9rdida, la esperanza sigue teniendo fuerza real."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Diablo III se presenta como el Se\u00f1or del Pecado?",o:["Azmodan", "Belial", "Duriel", "Mephisto"],a:0,exp:"Azmodan es el Se\u00f1or del Pecado y uno de los Males Menores.",extra:"Azmodan representa la corrupci\u00f3n por exceso, ambici\u00f3n y decadencia. En Diablo III lidera una invasi\u00f3n demon\u00edaca directa desde el cr\u00e1ter de Arreat."},
  {t:"m",q:"\u00bfQu\u00e9 villano de Diablo III se conoce como el Se\u00f1or de las Mentiras?",o:["Belial", "Azmodan", "Diablo", "Baal"],a:0,exp:"Belial es el Se\u00f1or de las Mentiras y manipula los eventos de Caldeum mediante enga\u00f1os.",extra:"Belial funciona como antagonista pol\u00edtico y de infiltraci\u00f3n. Su amenaza no est\u00e1 solo en su poder demon\u00edaco, sino en su capacidad de distorsionar la confianza."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad des\u00e9rtica es importante en el Acto II de Diablo III?",o:["Caldeum", "Tristram", "Harrogath", "Westmarch"],a:0,exp:"Caldeum es la gran ciudad del Acto II de Diablo III y escenario de intrigas relacionadas con Belial.",extra:"Caldeum combina lujo, comercio, pol\u00edtica y corrupci\u00f3n. Es uno de los lugares donde Diablo III muestra que el mal puede operar detr\u00e1s de palacios y cortes, no solo en mazmorras."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad g\u00f3tica es central en Reaper of Souls?",o:["Westmarch", "Lut Gholein", "Kurast", "Harrogath"],a:0,exp:"Westmarch es la ciudad principal de Reaper of Souls y escenario de la invasi\u00f3n de Malthael.",extra:"Westmarch tiene una est\u00e9tica oscura, urbana y desesperada que encaja con el tono de muerte de la expansi\u00f3n. Su ca\u00edda marca la amenaza global de Malthael."},
  {t:"m",q:"\u00bfQu\u00e9 concepto une a StarCraft, Warcraft y Diablo como sello cl\u00e1sico de Blizzard?",o:["Campa\u00f1as con fuerte identidad de facciones y personajes memorables", "Uso exclusivo de mundos hist\u00f3ricos reales", "Ausencia total de cinem\u00e1ticas", "Juegos sin modo multijugador"],a:0,exp:"Las tres sagas se caracterizan por facciones muy reconocibles, personajes ic\u00f3nicos y campa\u00f1as narrativas con cinem\u00e1ticas memorables.",extra:"Aunque pertenecen a g\u00e9neros distintos, StarCraft, Warcraft y Diablo comparten una construcci\u00f3n de mundo muy marcada: frases reconocibles, siluetas fuertes, h\u00e9roes tr\u00e1gicos y villanos enormes."},
  {t:"m",q:"\u00bfQu\u00e9 universo de Blizzard tiene como eje narrativo el Conflicto Eterno?",o:["StarCraft", "Warcraft", "Diablo", "Overwatch"],a:2,exp:"El Conflicto Eterno entre el Cielo y el Infierno es la base mitol\u00f3gica de Diablo.",extra:"Santuario nace precisamente como una salida a ese conflicto. Por eso la humanidad en Diablo no es accidental: es el resultado de una rebeli\u00f3n contra la guerra infinita entre \u00e1ngeles y demonios."},
  {t:"m",q:"\u00bfQu\u00e9 universo de Blizzard tiene como amenaza c\u00f3smica a Amon?",o:["Diablo", "StarCraft", "Warcraft", "Hearthstone"],a:1,exp:"Amon es una amenaza central de StarCraft II, vinculada a los Xel Naga y al destino de protoss y zerg.",extra:"Amon eleva el conflicto de StarCraft desde una guerra entre razas hacia una escala c\u00f3smica. Su plan afecta la creaci\u00f3n, la evoluci\u00f3n y la libertad de especies enteras."},
];

export default blizzardQuestions;
